const allResults = $input.first().json.data;

let totalLeads = 0;
let totalGold = 0;
const tradeBlocks = [];

for (const result of allResults) {
  if (!result.ok || !result.leads) continue;
  const leads = result.leads.sort((a, b) => (b.score || 0) - (a.score || 0));
  const goldLeads = leads.filter(l => l.revenueTier === 'gold');
  const worthLeads = leads.filter(l => l.revenueTier === 'worth-checking');
  totalLeads += leads.length;
  totalGold += goldLeads.length;
  const tradeName = leads[0]?.trade || 'unknown';
  tradeBlocks.push(`
<div style="border:1px solid #e5e7eb;border-radius:8px;padding:16px;margin:12px 0">
  <h3 style="margin:0 0 8px;text-transform:capitalize">${tradeName}</h3>
  <p style="margin:0 0 8px;color:#374151">${leads.length} leads &middot; ${goldLeads.length} gold &middot; near ${result.outward}</p>
  ${goldLeads.slice(0, 3).map(l =>
    `<div style="padding:6px 0;border-top:1px solid #f3f4f6">
      <strong>${l.title || 'Lead'}</strong> &mdash; ${l.location || l.postcodeOutward || ''} &mdash; Score ${l.score}
    </div>`
  ).join('')}
  ${goldLeads.length === 0 ? `<div style="color:#6b7280;font-size:13px">${worthLeads.length} worth-checking</div>` : ''}
</div>`);
}

const week = new Date().toLocaleDateString('en-GB', { day:'numeric', month:'long', year:'numeric' });
const html = `
<h1>JobFilter Weekly — ${week}</h1>
<p><strong>${totalLeads} total &middot; ${totalGold} gold</strong> across ${allResults.length} trade${allResults.length !== 1 ? 's' : ''}.</p>
${tradeBlocks.join('')}
<p style="color:#6b7280;font-size:12px">n8n weekly sweep</p>`;

return [{ json: { html, totalLeads, totalGold, tradeCount: allResults.length } }];
